314	/**
315	 * Validate aider-specific settings.
316	 * Throws on invalid types to catch config errors at load time.
317	 */
318	export function validateAiderSettings(
319	  aider: unknown,
320	): AiderSettings | undefined {
321	  if (aider == null) return undefined;
322	  if (typeof aider !== "object" || Array.isArray(aider)) {
323	    throw new Error("settings.run.aider must be an object");
324	  }
325	  const obj = aider as Record<string, unknown>;
326	  if (obj.model !== undefined && typeof obj.model !== "string") {
327	    throw new Error("settings.run.aider.model must be a string");
328	  }
329	  if (obj.editFormat !== undefined && typeof obj.editFormat !== "string") {
330	    throw new Error("settings.run.aider.editFormat must be a string");
331	  }
332	  if (obj.extraArgs !== undefined) {
333	    if (
334	      !Array.isArray(obj.extraArgs) ||
335	      !obj.extraArgs.every((a) => typeof a === "string")
336	    ) {
337	      throw new Error(
338	        "settings.run.aider.extraArgs must be an array of strings",
339	      );
340	    }
341	  }
342	  return obj as unknown as AiderSettings;
343	}
344	
345	/**
346	 * Get the current project settings
347	 *
348	 * Returns default settings if no settings file exists.
349	 */
350	export async function getSettings(): Promise<SequantSettings> {
351	  if (!(await fileExists(SETTINGS_PATH))) {
352	    return DEFAULT_SETTINGS;
353	  }
354	
355	  try {
356	    const content = await readFile(SETTINGS_PATH);
357	    const parsed = JSON.parse(content) as Partial<SequantSettings>;
358	
359	    // Validate aider settings if present
360	    const aiderSettings = validateAiderSettings(
361	      (parsed.run as Record<string, unknown> | undefined)?.aider,
362	    );
363	
364	    // Merge with defaults to ensure all fields exist
365	    return {
366	      version: parsed.version ?? DEFAULT_SETTINGS.version,
367	      run: {
368	        ...DEFAULT_SETTINGS.run,
369	        ...parsed.run,
370	        ...(aiderSettings !== undefined ? { aider: aiderSettings } : {}),
371	      },
372	      agents: {
373	        ...DEFAULT_AGENT_SETTINGS,
374	        ...parsed.agents,
375	      },
376	      scopeAssessment: {
377	        ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS,
378	        ...parsed.scopeAssessment,
379	        trivialThresholds: {
380	          ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS.trivialThresholds,
381	          ...parsed.scopeAssessment?.trivialThresholds,
382	        },
383	        thresholds: {
384	          ...DEFAULT_SCOPE_ASSESSMENT_SETTINGS.thresholds,
385	          ...parsed.scopeAssessment?.thresholds,
386	        },
387	      },
388	      qa: {
389	        ...DEFAULT_QA_SETTINGS,
390	        ...parsed.qa,
391	      },
392	    };
393	  } catch {
394	    return DEFAULT_SETTINGS;
395	  }
396	}
397	
398	/**
399	 * Save project settings
400	 */
401	export async function saveSettings(settings: SequantSettings): Promise<void> {
402	  await ensureDir(dirname(SETTINGS_PATH));
403	  await writeFile(SETTINGS_PATH, JSON.stringify(settings, null, 2));
404	}
405	
406	/**
407	 * Check if settings file exists
408	 */
409	export async function settingsExist(): Promise<boolean> {
410	  return fileExists(SETTINGS_PATH);
411	}
412	
413	/**
414	 * Create default settings file
415	 */
416	export async function createDefaultSettings(): Promise<void> {
417	  await saveSettings(DEFAULT_SETTINGS);
418	}
419	
