    const result = mergeBackSubWorktree(issueWorktreePath, sub);
    results.push(result);
    if (result.success) {
      merged++;
    } else {
      conflicts++;
    }
  }

  return { merged, conflicts, results };
}

/**
 * Remove a single sub-worktree and its branch.
 *
