/** @internal Log a non-fatal warning: one-line summary always, detail in verbose. */
export function logNonFatalWarning(
  message: string,
  error: unknown,
  verbose: boolean,
): void {
  console.log(chalk.yellow(message));
  if (verbose) {
    console.log(chalk.gray(`    ${error}`));
