        {
          path: `${issueWorktree}/.exec-agents/agent-0`,
          branch: "exec-agent-485-0",
          agentIndex: 0,
        },
        {
          path: `${issueWorktree}/.exec-agents/agent-1`,
          branch: "exec-agent-485-1",
          agentIndex: 1,
        },
      ];

      // Both have changes, both merge cleanly
      mockExecSync.mockImplementation((cmd) => {
